import{_ as a,o as e,c as i,ae as o}from"./chunks/framework.B6gjLfeO.js";const d=JSON.parse('{"title":"AIO App Attribution","description":"","frontmatter":{"title":"AIO App Attribution","slug":"ai-optimization-aio"},"headers":[],"relativePath":"account-hub/ai-optimization-aio.md","filePath":"account-hub/ai-optimization-aio.md"}'),r={name:"account-hub/ai-optimization-aio.md"};function n(s,t,p,u,h,c){return e(),i("div",null,[...t[0]||(t[0]=[o('<p>Branch now attributes traffic from AI chat assistants like ChatGPT, Claude, Perplexity, and more.</p><p>Branch has updated <a href="./seo-app-attribution.html">SEO App Attribution</a> to include <strong>AIO (AI Optimization)</strong>. This update expands Branch&#39;s organic reporting capabilities to capture and attribute traffic from the growing number of AI chat agents used for content discovery.</p><p>Users are increasingly turning to AI assistants to answer questions and find products. When these assistants surface a direct link to your website, the session often appears as generic or unattributed organic traffic. AIO solves this by identifying and attributing traffic from AI chat agents.</p><h2 id="what-is-aio-app-attribution" tabindex="-1">What is AIO App Attribution? <a class="header-anchor" href="#what-is-aio-app-attribution" aria-label="Permalink to &quot;What is AIO App Attribution?&quot;">​</a></h2><p>AIO App Attribution is an extension of the Branch SEO App Attribution feature. It allows the Branch SDK to identify when a user opens your app or website with a deep link that originates from a supported AI chat agent.</p><p>By recognizing specific referrer signals and UTM parameters used by these platforms, Branch can now attribute these sessions to the specific AI agent that drove the visit, rather than lumping them in with standard organic search or direct traffic.</p><h3 id="supported-ai-agents" tabindex="-1">Supported AI agents <a class="header-anchor" href="#supported-ai-agents" aria-label="Permalink to &quot;Supported AI agents&quot;">​</a></h3><p>With this release, we are introducing specific channel detection for the following major AI chat agents:</p><ul><li>ChatGPT</li><li>Gemini</li><li>Claude</li><li>Copilot</li><li>Perplexity</li></ul><h2 id="how-it-impacts-reporting" tabindex="-1">How it impacts reporting <a class="header-anchor" href="#how-it-impacts-reporting" aria-label="Permalink to &quot;How it impacts reporting&quot;">​</a></h2><p>This update unifies organic discovery reporting. In Branch, you will now see &quot;Organic Chat Agent&quot; alongside &quot;Organic Search&quot; within the same Analytics views. There are other benefits as well:</p><ul><li><strong>Granular attribution:</strong> You can distinguish between users who found you through a traditional search engine (for example, Google, Bing) and those who found you through an AI assistant (for example, ChatGPT).</li><li><strong>Content visibility:</strong> Just as with SEO, AIO attribution captures the <code>~organic_search_url</code>, allowing you to see exactly which piece of content the AI agent surfaced to drive the conversion.</li><li><strong>Data consistency:</strong> Traffic from AI agents is categorized under the <code>~feature</code> tag &quot;organic chat agent,&quot; keeping your data organized and distinct from traditional SEO traffic.</li></ul><p>This feature is designed to ensure your analytics reflect the reality of modern search behavior, giving you a complete picture of how users are discovering your app today.</p><h2 id="what-s-next" tabindex="-1">What&#39;s next? <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s next?&quot;">​</a></h2><h4 id="if-you-already-have-seo-app-attribution-set-up" tabindex="-1">If you already have SEO App Attribution set up <a class="header-anchor" href="#if-you-already-have-seo-app-attribution-set-up" aria-label="Permalink to &quot;If you already have SEO App Attribution set up&quot;">​</a></h4><p>AIO is now active automatically. View your AI chat agent traffic in Branch.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>If you don&#39;t see AIO data in Branch, you may need to clear your browser cache. Bookmarks and saved queries from before AIO was released are cached and may not load the new data. Try clearing your browser&#39;s cache to resolve this issue.</p></div><h4 id="if-you-don-t-have-seo-app-attribution-set-up" tabindex="-1">If you don’t have SEO App Attribution set up <a class="header-anchor" href="#if-you-don-t-have-seo-app-attribution-set-up" aria-label="Permalink to &quot;If you don’t have SEO App Attribution set up&quot;">​</a></h4><p>Learn how to set up SEO and AIO App Attribution in our <a href="https://help.branch.io/docs/seo-app-attribution" target="_blank" rel="noreferrer">SEO + AIO App Attribution</a> article.</p>',19)])])}const f=a(r,[["render",n]]);export{d as __pageData,f as default};
